arguments.new_str:
using System.ComponentModel;
using System.Windows.Forms;
using System.Windows.Forms.Design;
public class MyControl : UserControl
{
    [DefaultValue("")]
    public string DisplayName { get; set; } = "";

    [DefaultValue(0)]
    public int MaxItems { get; set; }

    private readonly StatusStrip _statusStrip;

    public MyControl()
    {
        _statusStrip = new StatusStrip();
        // .NET 9 changed the default renderer; set explicitly to preserve appearance.
        _statusStrip.RenderMode = ToolStripRenderMode.System;
        Controls.Add(_statusStrip);
    }

    /// <summary>
    /// Safely invokes DropDownControl, guarding against null which is
    /// no longer accepted in .NET 9 (parameter is now non-nullable).
    /// </summary>
    public void ShowDropDown(IWindowsFormsEditorService editorService, Control? control)
    {
        if (control is not null)
        {
            editorService.DropDownControl(control);
        }
    }
}

arguments.old_str:
using System.Net;
using System.Windows.Forms;
class ImageLoader
{
    void LoadImage(PictureBox pictureBox, string url)
    {
        try { pictureBox.Load(url); }
        catch (WebException ex) { Console.WriteLine("Failed: " + ex.Message); }
    }
}

arguments.new_str:
using System.Net.Http;
using System.Windows.Forms;
class ImageLoader
{
    void LoadImage(PictureBox pictureBox, string url)
    {
        // .NET 9: PictureBox now throws HttpRequestException/TaskCanceledException
        // instead of WebException when loading from URLs fails.
        try { pictureBox.Load(url); }
        catch (HttpRequestException ex) { Console.WriteLine("Failed: " + ex.Message); }
        catch (TaskCanceledException ex) { Console.WriteLine("Timeout: " + ex.Message); }
    }
}

